import json
raw = draft_json if isinstance(draft_json, str) else json.dumps(draft_json)
raw = raw.strip()
if raw.startswith('```'):
    nl = raw.find('\n')
    raw = raw[nl + 1:] if nl != -1 else raw
    end = raw.rfind('```')
    if end != -1:
        raw = raw[:end]
    raw = raw.strip()
try:
    parsed = json.loads(raw)
except Exception:
    parsed = {'decision': 'escalate', 'amount': 0, 'justification': 'unparseable draft'}
decision = str(parsed.get('decision', '')).lower()
try:
    amount = float(parsed.get('amount', 0))
except Exception:
    amount = 0.0
violation = decision == 'approve' and amount > 100
if violation:
    output = {
        'retry': 'Your previous draft auto-approved a refund of ' + str(amount) + ' USD, which violates the policy (max 100 USD for auto-approve). Choose decision="partial" with amount<=100, or decision="escalate". Return ONLY the JSON object.',
        '__colmena_loop_status': 'NEXT_TURN'
    }
else:
    output = {
        'approved': parsed,
        'decision_json': json.dumps(parsed),
        '__colmena_loop_status': 'FINISHED'
    }
